const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';
const auth = Buffer.from('admin:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj').toString('base64');

try {
  const response = await this.helpers.httpRequest({
    method: 'PROPFIND',
    url: `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/tasks/`,
    headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/xml', 'Depth': '1' },
    body: '<?xml version="1.0"?><d:propfind xmlns:d="DAV:"><d:prop><d:getetag/></d:prop></d:propfind>',
    returnFullResponse: true
  });

  const xml = response.body || response.data || '';
  const files = [];
  const hrefMatches = xml.match(/<d:href>([^<]*\.ics)<\/d:href>/gi) || [];
  for (const m of hrefMatches) {
    const href = m.match(/<d:href>([^<]*)<\/d:href>/i)[1];
    const filename = href.split('/').pop().replace('.ics', '');
    files.push({ filename, href });
  }
  return [{ json: { success: true, files, count: files.length } }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}

const nextcloudUrl = 'https://cloud.tal.ahmed-rezk.com';
const nextcloudUser = 'admin';
const auth = Buffer.from('admin:4EMsB-kQLNn-YdnCC-9Dd6Z-GA9jj').toString('base64');
const body = $('Set Config').first().json.body;
const taskId = Date.now();

const formatICalDate = (d) => {
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getUTCFullYear()}${pad(d.getUTCMonth()+1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`;
};
const parseDate = (s) => { if (!s) return null; const d = new Date(s); return isNaN(d.getTime()) ? null : d; };

const now = new Date();
const lines = ['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//n8n//Nextcloud//EN','BEGIN:VTODO',`UID:n8n-task-${taskId}`,`DTSTAMP:${formatICalDate(now)}`];

if (body.title) lines.push(`SUMMARY:${body.title}`);
if (body.description) lines.push(`DESCRIPTION:${body.description}`);
if (body.due) { const d = parseDate(body.due); if (d) lines.push(`DUE:${formatICalDate(d)}`); }
if (body.startDate) { const d = parseDate(body.startDate); if (d) lines.push(`DTSTART:${formatICalDate(d)}`); }
if (body.completed) { const d = parseDate(body.completed); if (d) lines.push(`COMPLETED:${formatICalDate(d)}`); }

if (body.status) {
  const statusMap = { 'todo': 'NEEDS-ACTION', 'in-progress': 'IN-PROCESS', 'completed': 'COMPLETED', 'cancelled': 'CANCELLED' };
  lines.push(`STATUS:${statusMap[body.status] || body.status}`);
} else {
  lines.push('STATUS:NEEDS-ACTION');
}

if (body.priority !== undefined) lines.push(`PRIORITY:${Math.min(9, Math.max(1, parseInt(body.priority)))}`);
if (body.percentComplete !== undefined) lines.push(`PERCENT-COMPLETE:${Math.min(100, Math.max(0, parseInt(body.percentComplete)))}`);
if (body.categories) lines.push(`CATEGORIES:${Array.isArray(body.categories) ? body.categories.join(',') : body.categories}`);
if (body.parentTaskUid) lines.push(`RELATED-TO;RELTYPE=PARENT:${body.parentTaskUid}`);
if (body.duration) lines.push(`DURATION:${body.duration}`);
if (body.recurrence) lines.push(`RRULE:${body.recurrence}`);
if (body.location) lines.push(`LOCATION:${body.location}`);

lines.push('END:VTODO','END:VCALENDAR');

const taskUrl = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/tasks/${taskId}.ics`;

try {
  const response = await this.helpers.httpRequest({
    method: 'PUT',
    url: taskUrl,
    headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'text/calendar' },
    body: lines.join('\r\n')
  });
  return [{ json: { success: true, message: 'Task created!', task: { uid: `n8n-task-${taskId}`, title: body.title, description: body.description || null, due: body.due || null, status: body.status || 'NEEDS-ACTION', priority: body.priority || null } } }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}

